import sailpoint.object.Identity;
import sailpoint.tools.Util;
import sailpoint.object.Bundle;
import sailpoint.api.Provisioner;
import sailpoint.object.Attributes;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningProject;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import org.apache.commons.logging.LogFactory;
import org.apache.commons.logging.Log;
import sailpoint.rapidapponboarding.logger.LogEnablement;
import sailpoint.api.*;
import sailpoint.object.*;


import org.apache.log4j.Logger;
import sailpoint.tools.Util;
import sailpoint.object.Filter;
import sailpoint.api.ObjectUtil;
import sailpoint.object.Identity;
import sailpoint.object.Attributes;
import sailpoint.object.Application;
import sailpoint.object.QueryOptions;
import sailpoint.object.TaskDefinition;
import sailpoint.tools.GeneralException;
import sailpoint.object.ProvisioningTransaction;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import java.text.DateFormat;
import java.text.SimpleDateFormat;
import java.util.Calendar;
import java.util.TimeZone;
import java.util.Date;
import sailpoint.object.EmailOptions;
import sailpoint.object.EmailTemplate;
import sailpoint.object.EmailFileAttachment;




TaskDefinition taskDef = context.getObjectByName(TaskDefinition.class, "PT-Details");
if (taskDef == null) {
  throw new GeneralException("TaskDefinition not exit");
}

String provTransactionId = taskDef.getString("provName");
List finalList = new ArrayList();
finalList.add("Identity,Application,Entitlement");
List listOfProperties = new ArrayList();

if (Util.isNullOrEmpty(provTransactionId)) {
  throw new GeneralException("latestProvisioningTransactionID is null or empty");
}

Filter filter = Filter.and(Filter.ge("id", provTransactionId), Filter.eq("source", "IdentityRefresh"));

QueryOptions qo = new QueryOptions();
qo.add(filter);
listOfProperties.add("id");
listOfProperties.add("name");
listOfProperties.add("identityName");
listOfProperties.add("applicationName");
listOfProperties.add("operation");

Iterator allIt = context.search(ProvisioningTransaction.class, qo, listOfProperties);
while (allIt.hasNext()) {
  Object[]obj = (Object[])allIt.next();
  String provId = (String)obj[0];
  String provName = (String)obj[1];
  String identityName = (String)obj[2];
  String applicationName = (String)obj[3];
  String operation = (String)obj[4];

  ProvisioningTransaction transaction = context.getObjectByName(ProvisioningTransaction.class, provName);
  Identity identity = context.getObjectByName(Identity.class, identityName);
  Application application = context.getObjectByName(Application.class, applicationName);

  if ("SAP".equalsIgnoreCase(applicationName) @or ("Create".equalsIgnoreCase(operation)  && ("AD_Active-Directory".equalsIgnoreCase(applicationName) @or "WBG - Azure AD".equalsIgnoreCase(applicationName) @or "IDM_LDAP-Linux".equalsIgnoreCase(applicationName) @or "SecurID Direct".equalsIgnoreCase(applicationName) ))) {


    if (transaction != null  && identity != null  && application != null) {

      if (application.getAccountSchema() != null) {

        List groupAttributes = application.getAccountSchema().getGroupAttributes();

        if (!Util.isEmpty(groupAttributes)) {

          Attributes txnAttrs = transaction.getAttributes();

          if (txnAttrs != null) {

            Object reqObj = txnAttrs.get("request");

            if (reqObj instanceof AccountRequest) {

              AccountRequest acctReq = (AccountRequest)reqObj;
              List attributeRequests = acctReq.getAttributeRequests();

              if (!Util.isEmpty(attributeRequests)) {

                for (AttributeRequest ar: Util.safeIterable(attributeRequests)) {

                  if (groupAttributes.contains(ar.getName())) {

                    List entitlements = new ArrayList();

                    if (ar.getValue()instanceof List) {
                      entitlements = (List)ar.getValue();
                    } else if (ar.getValue()instanceof String) {
                      entitlements.add(ar.getValue());
                    }

                    for (String entitlement: Util.safeIterable(entitlements)) {
                      finalList.add("\n" + identityName + "," + applicationName + "," + entitlement);
                    }

                  }
                }
              }
            }
          }
        }
      }
    }

  } else {

    if (transaction != null  && identity != null  && application != null) {

      if (application.getAccountSchema() != null) {

        List groupAttributes = application.getAccountSchema().getGroupAttributes();

        if (!Util.isEmpty(groupAttributes)) {

          Attributes txnAttrs = transaction.getAttributes();

          if (txnAttrs != null) {

            Object reqObj = txnAttrs.get("request");

            if (reqObj instanceof AccountRequest) {

              AccountRequest acctReq = (AccountRequest)reqObj;
              List attributeRequests = acctReq.getAttributeRequests();

              if (!Util.isEmpty(attributeRequests)) {

                for (AttributeRequest ar: Util.safeIterable(attributeRequests)) {

                  if (groupAttributes.contains(ar.getName())) {

                    List entitlements = new ArrayList();

                    if (ar.getValue()instanceof List) {
                      entitlements = (List)ar.getValue();
                    } else if (ar.getValue()instanceof String) {
                      entitlements.add(ar.getValue());
                    }

                    for (String entitlement: Util.safeIterable(entitlements)) {

                      String getBundleObjs =
                        "sql:select (select name from spt_bundle where id = bc.bundle)," +
                        "(select name from spt_bundle where id = bc.child) " +
                        "from SPT_BUNDLE_REQUIREMENTS bc " +
                        "join spt_profile p on bc.child = p.bundle_id " +
                        "join spt_profile_constraints pc on p.id = pc.profile " +
                        "where elt like '%" + entitlement + "%' " +
                        "and p.application = (select id from spt_application where name='" + applicationName + "')";

                      Iterator it2 = context.search(getBundleObjs, null, null);
                      List bundleNames = new ArrayList();

                      while (it2.hasNext()) {
                        Object[]rowTest = (Object[])it2.next();
                        bundleNames.add(rowTest[0]);
                      }

                      List assignedRoles = identity.getAssignedRoles();
                      List assignedRoleNames = ObjectUtil.getObjectNames(assignedRoles);

                      boolean found = false;

                      for (String brName: Util.safeIterable(bundleNames)) {
                        if (assignedRoleNames.contains(brName)) {
                          found = true;
                          break;
                        }
                      }

                      if (!found  && Util.nullSafeSize(bundleNames) > 0) {
                        finalList.add("\n" + identityName + "," + applicationName + "," + entitlement);
                        log.error("finalList " + finalList.size());
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

return finalList;

if (finalList != null @and finalList.size() > 0) {

  /// Generate date
  Calendar ca = Calendar.getInstance();
  TimeZone time_zone1 = TimeZone.getTimeZone("EST");
  ca.setTimeZone(time_zone1);

  DateFormat dateFormat1 = new SimpleDateFormat("MM-dd-yyyy");
  String currentDate = dateFormat1.format(ca.getTime());

  /// Filename with date
  String fileName = "ProvisioningTransaction-" + currentDate + ".csv";

  EmailOptions emailops = new EmailOptions();
  EmailTemplate snowTemplate = context.getObjectByName(EmailTemplate.class, "Provisioingtransections-GenericTicketEmail");

  String singleTicketDetails = finalList.toString().replace("[", "").replace("]", "");
  byte[]singleTicketDetailsDataByte = singleTicketDetails.getBytes();

  EmailFileAttachment finalListFileAttachment = new EmailFileAttachment(fileName, EmailFileAttachment.MimeType.MIME_CSV, singleTicketDetailsDataByte);
  emailops.addAttachment(finalListFileAttachment);
  emailops.setVariable("createIncident", "##CREATEINCIDENT##");
  emailops.setVariable("assignmentGroup", "SN-Enterprise Authentication");
  emailops.setTo("sshaik11@worldbankgroup.org");
  context.sendEmailNotification(snowTemplate, emailops);
}
